import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import { Tooltip } from '@components/tooltip';
import type { TooltipDefaultProps } from '@components/tooltip';
import { cva } from 'class-variance-authority';
import Pin from 'lucide-solid/icons/pin';
import PinOff from 'lucide-solid/icons/pin-off';
import Plus from 'lucide-solid/icons/plus';
import X from 'lucide-solid/icons/x';
import {
  Component,
  createEffect,
  createMemo,
  createSignal,
  createUniqueId,
  For,
  JSX,
  mergeProps,
  on,
  Show,
} from 'solid-js';
import { TabItem, TabProps } from './tab.types';
import { BaseColorProps } from '@/type';

const headerVariant = cva('', {
  variants: {
    variants: {
      lift: '',
      box: '',
      border: 'rounded-none p-0',
    },
    tabPlacement: { horizontal: '', vertical: '' },
    position: { top: '', bottom: '', left: '', right: '' },
  },
  compoundVariants: [
    {
      variants: 'lift',
      position: 'top',
      class: 'pb-0',
    },
    {
      variants: 'lift',
      position: 'bottom',
      class: 'pt-0',
    },
    {
      variants: 'lift',
      tabPlacement: 'vertical',
      position: 'left',
      class: 'pr-0 overflow-x-hidden',
    },
    {
      variants: 'lift',
      tabPlacement: 'vertical',
      position: 'right',
      class: 'pl-0 overflow-x-hidden',
    },
  ],
});

const DEFAULT_PROPS = {
  tabPlacement: 'horizontal' as const,
  position: 'top' as const,
  align: 'left' as const,
  variants: 'box' as const,
  canAdd: true,
  canPin: false,
  canRename: true,
  preRender: false,
  color: 'primary',
};

const TOOLTIP_CHAR_THRESHOLD = 19;

export const Tab: Component<TabProps> = props => {
  const p = mergeProps(DEFAULT_PROPS, props);
  const tabRootId = createUniqueId();

  // Active tab key
  const [activeKey, setActiveKey] = createSignal<string>(
    p.defaultActiveKey || p.items()[0]?.key || '',
  );

  // Rendered tabs tracking (for lazy rendering)
  const [renderedTabs, setRenderedTabs] = createSignal<Set<string>>(new Set());

  // Editing state for rename feature
  const [editingKey, setEditingKey] = createSignal<string | null>(null);
  const [editingValue, setEditingValue] = createSignal<string>('');

  // Compute position based on tabPlacement
  const computedPosition = createMemo(() => {
    if (p.tabPlacement === 'vertical') {
      return p.position === 'left' || p.position === 'right' ? p.position : 'left';
    }
    return p.position === 'top' || p.position === 'bottom' ? p.position : 'top';
  });

  // Sort items: pinned first, then unpinned (maintain order within each group)
  const sortedItems = createMemo(() => {
    const items = p.items();
    const pinned = items.filter(item => item.pinned);
    const unpinned = items.filter(item => !item.pinned);
    return [...pinned, ...unpinned];
  });

  // Check if there are both pinned and unpinned items (for separator)
  const hasPinnedAndUnpinned = createMemo(() => {
    const items = p.items();
    const hasPinned = items.some(item => item.pinned);
    const hasUnpinned = items.some(item => !item.pinned);
    return hasPinned && hasUnpinned;
  });

  // Get first unpinned item index in sorted list
  const firstUnpinnedIndex = createMemo(() => {
    const items = sortedItems();
    return items.findIndex(item => !item.pinned);
  });

  // Update active key when items change
  createEffect(
    on(
      () => p.items(),
      items => {
        if (items.length > 0 && !items.find(item => item.key === activeKey())) {
          setActiveKey(items[0].key);
        }
      },
    ),
  );

  // Mark tab as rendered when it becomes active
  createEffect(
    on(activeKey, key => {
      if (key && !renderedTabs().has(key)) {
        setRenderedTabs(prev => new Set([...prev, key]));
      }
    }),
  );

  // Handle tab click
  const handleTabClick = (item: TabItem) => {
    if (item.disabled) return;
    setActiveKey(item.key);
    p.onChange?.(item.key);
  };

  // Handle middle mouse click to close tab
  const handleMouseDown = (e: MouseEvent, item: TabItem) => {
    if (e.button === 1 && item.closable !== false) {
      e.preventDefault();
      handleRemoveTab(item);
    }
  };

  // Handle add tab
  const handleAddTab = () => {
    if (p.onAdd) {
      const newItem = p.onAdd();
      if (newItem) {
        p.setItems(prev => [...prev, newItem]);
        setActiveKey(newItem.key);
      }
    } else {
      // Default behavior: create a new tab
      const newKey = createUniqueId();
      const newItem: TabItem = {
        key: newKey,
        label: `Tab ${p.items().length + 1}`,
        children: <div>New Tab Content</div>,
      };
      p.setItems(prev => [...prev, newItem]);
      setActiveKey(newKey);
    }
  };

  // Handle remove tab
  const handleRemoveTab = async (item: TabItem) => {
    if (item.closable === false) return;

    const label = item.label || `Tab ${p.items().findIndex(i => i.key === item.key) + 1}`;

    if (p.onRemove) {
      const result = await p.onRemove(item.key, label);
      if (result === false) return;
    }

    const currentItems = p.items();
    const currentIndex = currentItems.findIndex(i => i.key === item.key);

    // If removing active tab, switch to adjacent tab
    if (activeKey() === item.key) {
      const nextItem = currentItems[currentIndex + 1] || currentItems[currentIndex - 1];
      if (nextItem) {
        setActiveKey(nextItem.key);
      }
    }

    p.setItems(prev => prev.filter(i => i.key !== item.key));

    // Clean up rendered tabs
    setRenderedTabs(prev => {
      const newSet = new Set(prev);
      newSet.delete(item.key);
      return newSet;
    });
  };

  // Handle pin/unpin tab
  const handlePinTab = (item: TabItem, e: MouseEvent) => {
    e.stopPropagation();
    const newPinned = !item.pinned;

    p.setItems(prev => prev.map(i => (i.key === item.key ? { ...i, pinned: newPinned } : i)));

    p.onPin?.(item.key, newPinned);
  };

  // Handle double-click to start editing
  const handleDoubleClick = (item: TabItem, e: MouseEvent) => {
    if (!p.canRename || item.disabled) return;
    e.stopPropagation();
    const label = item.label || `Tab ${p.items().findIndex(i => i.key === item.key) + 1}`;
    setEditingKey(item.key);
    setEditingValue(label);
  };

  // Handle rename input blur/submit
  const handleRenameSubmit = (item: TabItem) => {
    const newLabel = editingValue().trim();
    if (newLabel && newLabel !== item.label) {
      p.setItems(prev => prev.map(i => (i.key === item.key ? { ...i, label: newLabel } : i)));
      p.onRename?.(item.key, newLabel);
    }
    setEditingKey(null);
    setEditingValue('');
  };

  // Handle rename input keydown
  const handleRenameKeyDown = (item: TabItem, e: KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleRenameSubmit(item);
    } else if (e.key === 'Escape') {
      e.preventDefault();
      setEditingKey(null);
      setEditingValue('');
    }
  };

  // Check if tab should be rendered
  const shouldRenderContent = (item: TabItem) => {
    const isActive = activeKey() === item.key;
    const itemPreRender = item.pinned ? true : p.preRender;

    if (itemPreRender) {
      return renderedTabs().has(item.key) || isActive;
    }
    return isActive;
  };

  return (
    <div
      id={tabRootId}
      class={cn(
        'tab01',
        getColor(p.color!),
        `tab${p.variants === 'box' ? '23' : p.variants === 'lift' ? '24' : '25'}`,
        `tab${p.tabPlacement === 'horizontal' ? '17' : '18'}`,
        `tab${computedPosition() === 'top' ? '19' : computedPosition() === 'bottom' ? '20' : computedPosition() === 'left' ? '21' : '22'}`,
        p.class?.root,
      )}
    >
      {/* Tab Header */}
      <div
        class={cn(
          'tab02',
          `tab${p.align === 'left' ? '26' : p.align === 'center' ? '27' : '28'}`,
          headerVariant({
            variants: p.variants,
            tabPlacement: p.tabPlacement,
            position: p.position,
          }),
          p.class?.header,
        )}
      >
        <For each={sortedItems()}>
          {(item, index) => (
            <>
              {/* Separator between pinned and unpinned */}
              <Show when={hasPinnedAndUnpinned() && index() === firstUnpinnedIndex()}>
                <div class="tab14" />
              </Show>

              {/* Tab Item */}
              <div
                class={cn(
                  'tab03',
                  editingKey() === item.key && 'bg-base-100',
                  activeKey() === item.key && 'tab04',
                  item.pinned && 'tab05',
                  item.disabled && 'pointer-events-none opacity-50',
                  p.class?.item,
                )}
                onClick={() => handleTabClick(item)}
                onMouseDown={e => handleMouseDown(e, item)}
                onDblClick={e => handleDoubleClick(item, e)}
              >
                {/* Tab Icon */}
                <Show when={item.icon}>
                  <span class="tab06">{item.icon as Element}</span>
                </Show>

                {/* Tab Label */}
                <Show
                  when={editingKey() === item.key}
                  fallback={
                    <Show
                      when={p.useTooltip}
                      fallback={
                        <span class="tab07">
                          {item.label || `Tab ${p.items().findIndex(i => i.key === item.key) + 1}`}
                        </span>
                      }
                    >
                      {(() => {
                        const label =
                          item.label || `Tab ${p.items().findIndex(i => i.key === item.key) + 1}`;
                        const needsTooltip = label.length > TOOLTIP_CHAR_THRESHOLD;
                        if (!needsTooltip) {
                          return <span class="tab07">{label}</span>;
                        }
                        const opts = p.tooltipOptions ?? {};
                        const isCustom = 'customContent' in opts && opts.customContent != null;
                        const tooltipProps: Omit<TooltipDefaultProps, 'children'> = isCustom
                          ? {
                              type: 'default',
                              position: 'top' as const,
                              color: p?.color as BaseColorProps,
                              customContent: (opts as { customContent: JSX.Element }).customContent,
                            }
                          : {
                              type: 'default',
                              position: 'top' as const,
                              color: p?.color as BaseColorProps,
                              content: (opts as { content?: string }).content ?? label,
                            };
                        return (
                          <Tooltip {...(tooltipProps as TooltipDefaultProps)}>
                            <span class="tab07">{label}</span>
                          </Tooltip>
                        );
                      })()}
                    </Show>
                  }
                >
                  <input
                    ref={el =>
                      setTimeout(() => {
                        el?.focus();
                        el?.select();
                      }, 0)
                    }
                    type="text"
                    class="tab16"
                    value={editingValue()}
                    onInput={e => setEditingValue(e.currentTarget.value)}
                    onBlur={() => handleRenameSubmit(item)}
                    onKeyDown={e => handleRenameKeyDown(item, e)}
                    onClick={e => e.stopPropagation()}
                  />
                </Show>

                {/* Action Buttons */}
                <Show when={p.canPin || item.closable !== false}>
                  <div class="tab08">
                    {/* Pin Button */}
                    <Show when={p.canPin}>
                      <button
                        class="tab09 tab10"
                        onClick={e => handlePinTab(item, e)}
                        title={item.pinned ? 'Unpin tab' : 'Pin tab'}
                      >
                        <Show when={item.pinned} fallback={<Pin size={12} />}>
                          <PinOff size={12} />
                        </Show>
                      </button>
                    </Show>

                    {/* Close Button */}
                    <Show when={item.closable !== false}>
                      <button
                        class="tab09 tab11"
                        onClick={e => {
                          e.stopPropagation();
                          handleRemoveTab(item);
                        }}
                        title="Close tab"
                      >
                        <X size={12} />
                      </button>
                    </Show>
                  </div>
                </Show>
              </div>
            </>
          )}
        </For>

        {/* Add Button */}
        <Show when={p.canAdd}>
          <button
            class={cn('tab12', p.class?.addButton)}
            onClick={handleAddTab}
            title="Add new tab"
          >
            <Plus size={14} />
          </button>
        </Show>
      </div>

      {/* Tab Content */}
      <div class={cn('tab13', p.class?.content)}>
        <Show when={p.items().length === 0}>
          <div class="tab15">
            <span>No tabs available</span>
            <Show when={p.canAdd}>
              <button class="tab12" onClick={handleAddTab}>
                <Pin size={14} />
              </button>
            </Show>
          </div>
        </Show>

        <For each={p.items()}>
          {item => (
            <Show when={shouldRenderContent(item)}>
              <div class={cn('tab29 size-full', activeKey() !== item.key && 'hidden')}>
                {item.children as Element}
              </div>
            </Show>
          )}
        </For>
      </div>
    </div>
  );
};
